var model = pipeline.Fit(split.TrainSet);

// Evaluate — use full dataset if test set is too small for meaningful metrics
var evalData = split.TestSet;
var evalRowCount = mlContext.Data.CreateEnumerable<CustomerData>(evalData, reuseRowObject: false).Count();
if (evalRowCount < 5)
{
    Console.WriteLine($"Test set has only {evalRowCount} rows; evaluating on full dataset instead.");
    evalData = dataView;
}

try
{
    var predictions = model.Transform(evalData);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions);
    Console.WriteLine($"AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
}
catch (ArgumentOutOfRangeException)
{
    Console.WriteLine("Warning: Not enough data to compute evaluation metrics. Add more rows to customers.csv.");
}

