using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

// Load data
var dataView = mlContext.Data.LoadFromTextFile<CustomerDataRaw>(dataPath, hasHeader: true, separatorChar: ',');
var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);

// Build pipeline: map Yes/No → bool label, encode Region, combine features, train
var pipeline = mlContext.Transforms.Conversion.MapValue("Label",
        new[] { new KeyValuePair<string, bool>("Yes", true), new KeyValuePair<string, bool>("No", false) },
        inputColumnName: nameof(CustomerDataRaw.Churned))
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerDataRaw.Region)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerDataRaw.Age),
        nameof(CustomerDataRaw.Income),
        nameof(CustomerDataRaw.PurchaseHistory),
        "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.FastTree());

var model = pipeline.Fit(split.TrainSet);

// Evaluate — use full dataset if test set is too small
var evalData = split.TestSet;
var evalRowCount = mlContext.Data.CreateEnumerable<CustomerDataRaw>(evalData, reuseRowObject: false).Count();
if (evalRowCount < 5)
{
    Console.WriteLine($"Test set has only {evalRowCount} rows; evaluating on full dataset instead.");
    evalData = dataView;
}

try
{
    var predictions = model.Transform(evalData);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions);
    Console.WriteLine($"AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
}
catch (ArgumentOutOfRangeException)
{
    Console.WriteLine("Warning: Not enough data to compute evaluation metrics. Add more rows to customers.csv.");
}

// Save model and register pooled prediction engine
var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
mlContext.Model.Save(model, dataView.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API - POST to /predict");

app.MapPost("/predict", (PredictionEnginePool<CustomerInput, ChurnPrediction> pool, CustomerInput input) =>
{
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability,
    });
});

app.Run();

// Raw CSV row with string label
public class CustomerDataRaw
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = "";
}

// API input (no label needed)
public class CustomerInput
{
    public float Age { get; set; }
    public float Income { get; set; }
    public string Region { get; set; } = "";
    public float PurchaseHistory { get; set; }
    public string Churned { get; set; } = "";
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")] public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
}

